// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { SomniaEventHandler } from "@somnia-chain/reactivity-contracts/contracts/SomniaEventHandler.sol";

/**
 * @title RuleRegistryEventHandler
 * @notice Somnia on-chain reactivity handler for RuleRegistry RuleCreated events.
 * @dev When a rule is created on RuleRegistry, the Somnia chain invokes this handler
 *      (if a subscription is active). Use the SDK or precompile to subscribe to
 *      RuleCreated from your RuleRegistry address.
 *      Docs: https://docs.somnia.network/developer/reactivity/tutorials/solidity-on-chain-reactivity-tutorial
 */
contract RuleRegistryEventHandler is SomniaEventHandler {
    /// @notice RuleRegistry contract to listen to (set in constructor).
    address public immutable ruleRegistry;

    /// @notice Emitted when this handler reacts to a RuleCreated event.
    event ReactedToRuleCreated(
        uint256 indexed ruleId,
        bytes32 indexed id,
        string asset,
        string condition,
        uint256 targetPriceUsd,
        uint256 createdAt
    );

    /// @notice Canonical topic0 for RuleCreated(uint256,bytes32,string,string,uint256,uint256)
    bytes32 public constant RULE_CREATED_TOPIC =
        keccak256("RuleCreated(uint256,bytes32,string,string,uint256,uint256)");

    /**
     * @param _ruleRegistry Address of the RuleRegistry contract to react to.
     */
    constructor(address _ruleRegistry) {
        require(_ruleRegistry != address(0), "RuleRegistryEventHandler: zero registry");
        ruleRegistry = _ruleRegistry;
    }

    /**
     * @notice Called by the Somnia reactivity precompile when a subscribed event matches.
     * @dev Only processes RuleCreated events from the configured RuleRegistry.
     *      Keeps gas low; avoid reentrancy or emitting events that re-trigger this handler.
     */
    function _onEvent(
        address emitter,
        bytes32[] calldata eventTopics,
        bytes calldata data
    ) internal override {
        if (emitter != ruleRegistry) return;
        if (eventTopics.length < 1 || eventTopics[0] != RULE_CREATED_TOPIC) return;

        // RuleCreated: indexed ruleId (topic1), indexed id (topic2), data = (asset, condition, targetPriceUsd, createdAt)
        uint256 ruleId = eventTopics.length > 1 ? uint256(eventTopics[1]) : 0;
        bytes32 id = eventTopics.length > 2 ? eventTopics[2] : bytes32(0);
        (string memory asset, string memory condition, uint256 targetPriceUsd, uint256 createdAt) =
            abi.decode(data, (string, string, uint256, uint256));

        emit ReactedToRuleCreated(ruleId, id, asset, condition, targetPriceUsd, createdAt);
    }
}

